/**
 * One-off entry for esbuild to emit `frf-mesh-fold-16.png` next to classical goldens.
 * Build: npx esbuild scripts/write-frf-style-golden-entry.ts --bundle --platform=node --format=cjs --outfile=/tmp/frf-style-golden.cjs
 * Run: cd open-source/gnosis/distributed-inference-host && node /tmp/frf-style-golden.cjs
 */
import { writeFileSync, mkdirSync } from 'node:fs';
import { join } from 'node:path';
import { rgbFloat01InterleavedToPngBuffer } from '../__tests__/helpers/rgb-float01-to-png';
import { forkRaceFoldStyleTransfer } from '../src/forkRaceFoldStyleTransfer';

function makePlane(w: number, h: number, seed: number): Float32Array {
  const out = new Float32Array(w * h * 3);
  let s = seed >>> 0;
  const rand = () => {
    s = (s * 1664525 + 1013904223) >>> 0;
    return s / 0xffffffff;
  };
  for (let i = 0; i < out.length; i++) out[i] = rand();
  return out;
}

const GOLDEN_DIR = join(process.cwd(), '__tests__', 'golden', 'style-transfer');

void (async () => {
  mkdirSync(GOLDEN_DIR, { recursive: true });
  const w = 16;
  const h = 16;
  const content = makePlane(w, h, 7);
  const style = makePlane(w, h, 8);
  const frf = await forkRaceFoldStyleTransfer({
    content: { data: content, width: w, height: h, channels: 3 },
    style: { data: style, width: w, height: h, channels: 3 },
    meshFoldRankWeights: { topology: 0.35, depth: 0.1 },
    configs: [
      {
        label: 'lo',
        options: {
          method: 'classical',
          strength: 0.55,
          structurePreservation: 0.4,
          alphaWave: false,
          meshGate: { enabled: true },
        },
      },
      {
        label: 'hi',
        options: {
          method: 'classical',
          strength: 0.92,
          structurePreservation: 0.4,
          alphaWave: false,
          meshGate: { enabled: true },
        },
      },
    ],
  });
  writeFileSync(
    join(GOLDEN_DIR, 'frf-mesh-fold-16.png'),
    rgbFloat01InterleavedToPngBuffer(frf.stylized, w, h),
  );
})();
